+function getEffectiveSharedGatewayAuth(config: OpenClawConfig): {
+  mode: "token" | "password";
+  secret: string | undefined;
+} | null {
+  const resolvedAuth = resolveGatewayAuth({
+    authConfig: config.gateway?.auth,
